#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int Q; scanf("%d", &Q);
        long long *st = NULL, *mn = NULL;
        int topSt = -1, topMn = -1;
        for (int i = 0; i < Q; ++i) {
            char cmd[10]; scanf("%s", cmd);
            if (strcmp(cmd, "push") == 0) {
                long long x; scanf("%lld", &x);
                st = realloc(st, sizeof(long long)*(topSt+2));
                st[++topSt] = x;
                if (topMn == -1 || x <= mn[topMn]) {
                    mn = realloc(mn, sizeof(long long)*(topMn+2));
                    mn[++topMn] = x;
                }
                printf("None\n");
            } else if (strcmp(cmd, "pop") == 0) {
                if (st[topSt] == mn[topMn]) --topMn;
                --topSt;
                printf("None\n");
            } else if (strcmp(cmd, "top") == 0) {
                printf("%lld\n", st[topSt]);
            } else if (strcmp(cmd, "getMin") == 0) {
                printf("%lld\n", mn[topMn]);
            }
        }
        free(st);
        free(mn);
    }
    return 0;
}

