import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int Q = Integer.parseInt(br.readLine().trim());
            Deque<Long> st = new ArrayDeque<>();
            Deque<Long> mn = new ArrayDeque<>();
            for (int i = 0; i < Q; i++) {
                String line = br.readLine();
                StringTokenizer stz = new StringTokenizer(line);
                String cmd = stz.nextToken();
                switch (cmd) {
                    case "push":
                        long val = Long.parseLong(stz.nextToken());
                        st.addLast(val);
                        if (mn.isEmpty() || val <= mn.peekLast()) mn.addLast(val);
                        out.append("None\n");
                        break;
                    case "pop":
                        long top = st.removeLast();
                        if (top == mn.peekLast()) mn.removeLast();
                        out.append("None\n");
                        break;
                    case "top":
                        out.append(st.peekLast()).append('\n');
                        break;
                    case "getMin":
                        out.append(mn.peekLast()).append('\n');
                        break;
                }
            }
        }
        System.out.print(out.toString());
    }
}

