import sys

def main():
    data = sys.stdin.read().strip().split('\n')
    if not data:
        return
    idx = 0
    T = int(data[idx]); idx += 1
    out_lines = []
    for _ in range(T):
        Q = int(data[idx]); idx += 1
        st = []
        mn = []
        for __ in range(Q):
            parts = data[idx].split(); idx += 1
            cmd = parts[0]
            if cmd == 'push':
                x = int(parts[1])
                st.append(x)
                if not mn or x <= mn[-1]:
                    mn.append(x)
                out_lines.append('None')
            elif cmd == 'pop':
                if st[-1] == mn[-1]:
                    mn.pop()
                st.pop()
                out_lines.append('None')
            elif cmd == 'top':
                out_lines.append(str(st[-1]))
            elif cmd == 'getMin':
                out_lines.append(str(mn[-1]))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

